package github.chains;

import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.ImportDeclaration;
import com.github.javaparser.ast.NodeList;
import com.github.javaparser.ast.expr.Name;
import com.github.javaparser.ast.expr.NameExpr;
import com.github.javaparser.ast.stmt.ExpressionStmt;
import com.github.javaparser.ast.stmt.Statement;
import com.github.javaparser.ast.type.ClassOrInterfaceType;
import com.github.javaparser.ast.visitor.ModifierVisitor;
import com.github.javaparser.ast.visitor.Visitable;

import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.List;
import java.util.Optional;
import java.util.stream.Collectors;
import java.util.stream.Stream;

public class Main {
    public static void main(String[] args) throws IOException {
        if (args.length < 1) {
            System.out.println("Usage: java Main <source_directory>");
            System.exit(1);
        }

        String sourceDirectory = args[0];
        Path sourcePath = Paths.get(sourceDirectory);

        if (!Files.exists(sourcePath)) {
            System.out.println("Source directory does not exist: " + sourceDirectory);
            System.exit(1);
        }

        // Process all Java files in the directory recursively
        try (Stream<Path> paths = Files.walk(sourcePath)
                .filter(Files::isRegularFile)
                .filter(path -> path.toString().endsWith(".java"))) {

            List<Path> javaFiles = paths.collect(Collectors.toList());

            for (Path javaFile : javaFiles) {
                processJavaFile(javaFile);
            }
        }

        System.out.println("Transformation completed for all Java files in " + sourceDirectory);
    }

    private static void processJavaFile(Path javaFile) throws IOException {
        CompilationUnit cu = StaticJavaParser.parse(javaFile);

        // Create a visitor to transform imports
        ImportVisitor importVisitor = new ImportVisitor();
        cu.accept(importVisitor, null);

        // Save the updated file
        cu.setStorage(javaFile);
        cu.save();
    }

    /**
     * Visitor to handle the transformation of javax.interceptor imports to jakarta.interceptor
     */
    private static class ImportVisitor extends ModifierVisitor<Void> {
        @Override
        public Visitable visit(ImportDeclaration importDeclaration, Void arg) {
            // Check if this is a javax.interceptor import
            if (importDeclaration.getNameAsString().startsWith("javax.interceptor")) {
                // Replace with jakarta.interceptor
                String newImport = importDeclaration.getNameAsString().replace("javax.interceptor", "jakarta.interceptor");
                importDeclaration.setName(newImport);
            }
            return super.visit(importDeclaration, arg);
        }
    }
}

